def sample_log_tail_distribution(num_coeffs):
  coeffs, counts = [], [0]
  for _ in range(num_coeffs):
    min_time = iv.inf
    for i, count in enumerate(counts, start=1):
      time = (count+1) / pdf(i)
      if time < min_time:
        min_index, min_time = i, time
    if min_index == len(counts):
      counts.append(0)
